/**
 * Implementation notes:
 * This problem requires finding the k-th remaining element in an infinite sequence of positive even numbers (2, 4, 6, ...),
 * after removing specific even numbers found in a given range nums[l..r].
 * 
 * The core idea is to find the smallest positive integer m such that the number of remaining even numbers less than or equal to 2m is at least k.
 * The number of remaining evens <= 2m is (m - 1) - (Count of removed evens < 2m) + (1 if 2m is not removed).
 * More simply, we seek m such that m - C_{<2m} >= k, where C_{<2m} is the count of even numbers in nums[l..r] strictly less than 2m.
 * 
 * Since we have range queries (l, r) and value constraints (2m), we use a Persistent Segment Tree (PST).
 * 1. Preprocessing: We identify all even numbers in nums, map them to ranks (1 to M, where M is the count of evens).
 * 2. PST Construction: We build M prefix segment trees. PST_roots[i] stores counts of even numbers found in nums[0..i], indexed by their rank.
 * 3. Query: For a query [l, r, k], we binary search for m. In each step, we use the PST to find C_{<2m} = Query(PST_roots[r], 2m) - Query(PST_roots[l-1], 2m).
 * 
 * Complexity: O(N log M) for preprocessing, O(Q log(K+M) log M) for queries. This is efficient enough for N, Q <= 10^5.
 */

function solve(nums, queries) {

    // --- Step 1: Preprocessing - Identify even numbers and ranks ---

    const evenNumbers = [];
    for (const x of nums) {
        if (x % 2 === 0) {
            evenNumbers.push(x);
        }
    }

    // V_even is the sorted list of all even numbers in nums
    evenNumbers.sort((a, b) => a - b);
    const M = evenNumbers.length; // Number of distinct even numbers

    // Map value to rank (1-indexed)
    const valueToRank = new Map();
    for (let i = 0; i < M; i++) {
        // Rank is 1-based index in evenNumbers array
        valueToRank.set(evenNumbers[i], i + 1);
    }

    // --- Persistent Segment Tree (PST) Implementation ---

    // Node structure: { count: number, left: Node | null, right: Node | null }

    // Global array to store roots of the persistent versions
    const pstRoots = new Array(nums.length).fill(null);

    // Base empty node structure
    const EMPTY_NODE = { count: 0, left: null, right: null };

    /**
     * Updates the PST by incrementing the count at a specific rank index in a given tree structure.
     * Returns the root of the new, updated tree version.
     * @param {Object} prevNode - The node from the previous version.
     * @param {number} L - Start of the range (rank 1).
     * @param {number} R - End of the range (rank M).
     * @param {number} targetRank - The rank to update.
     * @returns {Object} The new node.
     */
    function update(prevNode, L, R, targetRank) {
        // Create a new node based on the previous one
        const newNode = { ...prevNode };
        newNode.count += 1;

        if (L === R) {
            return newNode;
        }

        const Mid = Math.floor((L + R) / 2);

        if (targetRank <= Mid) {
            // Go left: Copy right child, recurse on left child
            const newLeft = update(prevNode.left || EMPTY_NODE, L, Mid, targetRank);
            newNode.left = newLeft;
        } else {
            // Go right: Copy left child, recurse on right child
            const newRight = update(prevNode.right || EMPTY_NODE, Mid + 1, R, targetRank);
            newNode.right = newRight;
        }
        return newNode;
    }

    /**
     * Queries the sum of counts in the range [1, queryRank] for a specific PST root.
     * @param {Object} node - The root node of the tree version to query.
     * @param {number} L - Start of the range (rank 1).
     * @param {number} R - End of the range (rank M).
     * @param {number} queryRank - The upper bound rank (inclusive).
     * @returns {number} The sum of counts.
     */
    function query(node, L, R, queryRank) {
        if (!node || queryRank < L) {
            return 0;
        }
        // If the node range is fully contained in the query range [1, queryRank]
        if (R <= queryRank) {
            return node.count;
        }

        const Mid = Math.floor((L + R) / 2);
        let sum = 0;

        // Query left half
        sum += query(node.left || EMPTY_NODE, L, Mid, queryRank);

        // Query right half, only if necessary
        if (queryRank > Mid) {
            sum += query(node.right || EMPTY_NODE, Mid + 1, R, queryRank);
        }

        return sum;
    }

    // Build the PST versions
    let currentRoot = EMPTY_NODE;
    pstRoots[0] = currentRoot; // Initialize T_{-1} effectively

    for (let i = 0; i < nums.length; i++) {
        let prevRoot = i > 0 ? pstRoots[i-1] : EMPTY_NODE;
        let nextRoot = prevRoot;

        if (nums[i] % 2 === 0) {
            const rank = valueToRank.get(nums[i]);
            // Update the previous root to get the new root for index i
            nextRoot = update(prevRoot, 1, M, rank);
        }
        // Store the root for prefix up to index i
        pstRoots[i] = nextRoot;
    }

    // Handle the base case T_{-1} (represented by pstRoots[0] if we shift indices, but let's use the array indices directly)
    // pstRoots[i] now holds the state after processing nums[i].
    // We need a helper function to query range [l, r]
    const getCountRemovedLessThanV = (l, r, V) => {
        if (l > r) return 0;

        // Find the rank corresponding to the largest even number strictly less than V.
        // We use binary search on evenNumbers array (0-indexed).
        let low = 0;
        let high = M - 1;
        let rankLimit = 0; // 0 means no evens less than V

        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            if (evenNumbers[mid] < V) {
                // This number is smaller, potentially the largest one
                rankLimit = mid + 1; // Convert 0-indexed mid to 1-indexed rank
                low = mid + 1;
            } else {
                high = mid - 1;
