        // Query on T_r
        const countR = query(pstRoots[r], 1, M, rankLimit);

        // Query on T_{l-1}. If l=0, this is the empty prefix, which we model by using EMPTY_NODE.
        let countLMinus1 = 0;
        if (l > 0) {
            countLMinus1 = query(pstRoots[l - 1], 1, M, rankLimit);
        }

        return countR - countLMinus1;
    }


    // --- Step 2: Process Queries ---

    const results = [];

    for (const [l, r, k] of queries) {
        // Binary Search for m: we seek the smallest m such that m - C_{<2m} >= k

        // Lower bound for m: k (if no elements are removed)
        let lowM = 1;

        // Upper bound for m: k + M + 1 is safe, since C <= M
        // Max k is 10^9. Max M is 10^5.
        let highM = k + M + 2; 

        let ansM = highM; 

        while (lowM <= highM) {
            const m = Math.floor((lowM + highM) / 2);
            const V = 2 * m;

            // C is the count of removed even numbers strictly less than 2m
            const C = getCountRemovedLessThanV(l, r, V);

            // Check condition: Is the count of remaining elements <= 2m at least k?
            const remainingCount = m - C;

            if (remainingCount >= k) {
                // m is potentially the answer, try smaller m
                ansM = m;
                highM = m - 1;
            } else {
                // m is too small, need more elements
                lowM = m + 1;
            }
        }

        // The result is 2 * ansM
        results.push(2 * ansM);
    }

    return results;
}
