 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const N = nums.length;

    // 1. Preprocessing: Calculate prefix sums of even numbers
    // P[i] stores the count of even numbers in nums[0...i-1]
    const P = new Array(N + 1).fill(0);
    for (let i = 0; i < N; i++) {
        P[i + 1] = P[i] + (nums[i] % 2 === 0 ? 1 : 0);
    }

    /**
     * Binary searches to find the largest index j such that nums[j] <= A.
     * Returns -1 if all elements are > A.
     * @param {number} A 
     * @returns {number} Index j
     */
    const getIndexLE = (A) => {
        let low = 0;
        let high = N - 1;
        let result = -1;

        while (low <= high) {
            // Use safe calculation for mid
            let mid = low + Math.floor((high - low) / 2);

            if (nums[mid] <= A) {
                result = mid;
                low = mid + 1; // Try to find a larger index
            } else {
                high = mid - 1;
            }
        }
        return result;
    };

    /**
     * Calculates C(A): count of even numbers in nums[l..r] that are <= A.
     * @param {number} A 
     * @param {number} l 
     * @param {number} r 
     * @returns {number} Count C(A)
     */
    const countEvenLE = (A, l, r) => {
        // 1. Find index j of largest element <= A
        const j = getIndexLE(A);

        // 2. Determine the effective upper bound R'
        let R_prime = Math.min(r, j);

        // 3. Check if the range is valid
        if (l > R_prime) {
            return 0;
        }

        // 4. Calculate count using prefix sums P[R'+1] - P[l]
        // P uses 1-based indexing for array length, so R_prime + 1 is the correct index.
        return P[R_prime + 1] - P[l];
    };

    const results = [];

    for (const query of queries) {
        const [l, r, k] = query;

        // We search for Y = A/2, where A is the target even number.
        // We seek the smallest Y such that Y >= k + C(2Y).

        // Lower bound for Y: k (since A >= 2k)
        let low_Y = k;

        // Upper bound for Y: k + N + 1. Max k is 10^9, max N is 10^5.
        // Using 2*10^9 + 1 is a safe bound for 64-bit integers, and fits standard JS number type safely here.
        let high_Y = 2 * 10**9 + N + 1; 
        let ans_Y = high_Y;

        while (low_Y <= high_Y) {
            let mid_Y = low_Y + Math.floor((high_Y - low_Y) / 2);

            // A = 2 * mid_Y
            const A = 2 * mid_Y;

            // C(A): count of even numbers in nums[l..r] <= A
            const C_A = countEvenLE(A, l, r);

            // Required rank if A=2*mid_Y is the answer: k + C(A)
            const required_rank_Y = k + C_A;

            // If mid_Y is large enough, it means the actual rank (required_rank_Y) is <= mid_Y.
            // Since we seek the smallest Y such that Y >= required_rank_Y, we try to go smaller.
            if (mid_Y >= required_rank_Y) {
                ans_Y = mid_Y;
                high_Y = mid_Y - 1;
            } else {
                // mid_Y is too small, rank is higher than mid_Y
                low_Y = mid_Y + 1;
            }
        }

        // The result A is 2 * ans_Y
        results.push(2 * ans_Y);
    }

    return results;
}
